CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE SCHEMA IF NOT EXISTS usuarios;
CREATE SCHEMA IF NOT EXISTS aplicacion;
CREATE TABLE IF NOT EXISTS usuarios.cuentas (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), gateway_id TEXT NOT NULL UNIQUE, nombre TEXT NOT NULL, email TEXT NOT NULL UNIQUE, password_hash TEXT NOT NULL, api_key_hash TEXT NOT NULL, runner_key_hash TEXT NOT NULL, rol TEXT NOT NULL DEFAULT 'admin', idioma TEXT NOT NULL DEFAULT 'es', estado TEXT NOT NULL DEFAULT 'activo', creado_en TIMESTAMPTZ NOT NULL DEFAULT now(), actualizado_en TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS usuarios.sesiones (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), cuenta_id UUID NOT NULL REFERENCES usuarios.cuentas(id) ON DELETE CASCADE, token_hash TEXT, ip TEXT, user_agent TEXT, creado_en TIMESTAMPTZ NOT NULL DEFAULT now(), expira_en TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS usuarios.auditoria (id BIGSERIAL PRIMARY KEY, cuenta_id UUID REFERENCES usuarios.cuentas(id) ON DELETE SET NULL, gateway_id TEXT, accion TEXT NOT NULL, detalle JSONB NOT NULL DEFAULT '{}'::jsonb, creado_en TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS aplicacion.runners (id TEXT NOT NULL, gateway_id TEXT NOT NULL REFERENCES usuarios.cuentas(gateway_id) ON DELETE CASCADE, estado TEXT NOT NULL DEFAULT 'offline', ultimo_estado TEXT, ultima_vez TIMESTAMPTZ, workspace_root TEXT, workspace_roots JSONB NOT NULL DEFAULT '[]'::jsonb, plataforma TEXT, hostname TEXT, version TEXT, max_concurrent_jobs INTEGER NOT NULL DEFAULT 1, trabajos_activos JSONB NOT NULL DEFAULT '[]'::jsonb, capacidades JSONB NOT NULL DEFAULT '[]'::jsonb, metricas JSONB NOT NULL DEFAULT '{}'::jsonb, creado_en TIMESTAMPTZ NOT NULL DEFAULT now(), actualizado_en TIMESTAMPTZ NOT NULL DEFAULT now(), PRIMARY KEY (gateway_id, id));
CREATE TABLE IF NOT EXISTS aplicacion.jobs (id TEXT PRIMARY KEY, gateway_id TEXT NOT NULL REFERENCES usuarios.cuentas(gateway_id) ON DELETE CASCADE, tipo TEXT NOT NULL, estado TEXT NOT NULL, runner_target TEXT NOT NULL, claimed_by TEXT, payload JSONB NOT NULL DEFAULT '{}'::jsonb, prioridad INTEGER NOT NULL DEFAULT 0, nota TEXT, exit_code INTEGER, resumen TEXT, error TEXT, stdout_tail TEXT DEFAULT '', stderr_tail TEXT DEFAULT '', resultado JSONB, truncado BOOLEAN NOT NULL DEFAULT false, local_log_path TEXT, needs_approval_at TIMESTAMPTZ, creado_en TIMESTAMPTZ NOT NULL DEFAULT now(), actualizado_en TIMESTAMPTZ NOT NULL DEFAULT now(), iniciado_en TIMESTAMPTZ, terminado_en TIMESTAMPTZ);
CREATE INDEX IF NOT EXISTS idx_jobs_gateway_estado ON aplicacion.jobs(gateway_id, estado, actualizado_en DESC);
CREATE INDEX IF NOT EXISTS idx_jobs_runner_estado ON aplicacion.jobs(gateway_id, runner_target, estado, prioridad DESC, creado_en ASC);
CREATE INDEX IF NOT EXISTS idx_runners_gateway ON aplicacion.runners(gateway_id, actualizado_en DESC);
CREATE TABLE IF NOT EXISTS aplicacion.servicios_manuales (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), gateway_id TEXT NOT NULL REFERENCES usuarios.cuentas(gateway_id) ON DELETE CASCADE, nombre TEXT NOT NULL, runner_target TEXT NOT NULL, cwd TEXT NOT NULL, comando TEXT NOT NULL, pid_file TEXT, out_log TEXT, err_log TEXT, activo BOOLEAN NOT NULL DEFAULT true, creado_en TIMESTAMPTZ NOT NULL DEFAULT now(), actualizado_en TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS aplicacion.configuracion (gateway_id TEXT PRIMARY KEY REFERENCES usuarios.cuentas(gateway_id) ON DELETE CASCADE, datos JSONB NOT NULL DEFAULT '{}'::jsonb, actualizado_en TIMESTAMPTZ NOT NULL DEFAULT now());
